module mux8to1 (
    input [7:0] obf_data,
    input [2:0] sel,
    output reg out
);
    always @(*) begin
        case (sel)
            3'b000: out = obf_data[0];
            3'b001: out = obf_data[1];
            3'b010: out = obf_data[2];
            3'b011: out = obf_data[3];
            3'b100: out = obf_data[4];
            3'b101: out = obf_data[5];
            3'b110: out = obf_data[6];
            3'b111: out = obf_data[7];
            default: out = 1'b0; // Default case for safety
        endcase
    end
endmodule
